UPDATE stage_prompts SET config = '{"stage":3,"laneTitle":"Visual & Music","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"GLOBAL ART DIRECTION\n\nEvery generated sheet belongs to the same Production Bible.\n\nVisual Identity\n• Apple keynote quality\n• A24 cinematic minimalism\n• Pixar pre-production documentation\n• Weta Workshop production bible\n• Netflix concept art presentation\n• Cannes Lions advertising pitch deck\n\nGraphic Language\n• White premium background\n• Thin black divider lines\n• Spacious layout\n• Elegant typography\n• Soft paper texture\n• Production asset numbering\n• Version numbers\n• Revision labels\n• Project title placeholder\n• Copyright footer\n\nEvery page should feel like it was created by an elite commercial art department for a $10M production."},"items":{"character":{"label":"Character","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now — this pass only fixes the output instruction. Revisit content later if needed.","content":{"geminiInstruction":"Describe the character for use as a visual reference: gender, age, skin tone, hair, outfit. A short, specific, production-usable description — not a placeholder.","fieldsSchema":[{"key":"gender","label":"Gender","type":"pill","options":["Female","Male","Non-binary"]},{"key":"age","label":"Age","type":"number"},{"key":"skin_tone","label":"Skin tone","type":"pill","options":["Fair","Wheatish","Dusky","Dark"]},{"key":"hair","label":"Hair","type":"text"},{"key":"outfit","label":"Outfit","type":"text"}]},"outputInstructions":[{"key":"master_character_sheet","label":"Master Character Sheet","default":true,"text":"Create a Premium Film Character Design Sheet based ONLY on the character description provided below.\n\nOBJECTIVE\nVisualize the described character as a single production-ready portrait for a high-end advertising film.\n\nART DIRECTION\n• Hollywood pre-production design bible\n• Premium concept art\n• Realistic digital painting\n• White museum-quality background\n• Luxury editorial layout\n• Apple-level presentation\n• Pixar / Weta / ILM production documentation\n\nDISPLAY — ONE portrait only, nothing else:\n• Hero Portrait — a single, clear, front-facing full-body view showing exactly the described gender, age, skin tone, hair, and outfit\n\nFIELD DISCIPLINE (critical)\n• Only depict details that are actually in the character description below — never invent costume elements, accessories, or props that weren''t described.\n• Do not generate additional angles, turnarounds, close-ups, or expression/pose strips — one portrait, one image.\n\nANNOTATIONS\nUse elegant arrows describing clothing, materials, accessories, and distinguishing features, only where the description actually specifies them.\n\nGRAPHIC DESIGN\nAsset Code • Version • Revision • Copyright Footer\n\nOUTPUT\nGenerate ONE premium character portrait image suitable for a Hollywood commercial production bible — a single image, not a multi-view sheet."}]},"property":{"label":"Property","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now.","content":{"geminiInstruction":"Describe the property/prop for use as a visual reference. A short, specific, production-usable description — not a placeholder.","fieldsSchema":[{"key":"description","label":"Description","type":"textarea"}]},"outputInstructions":[{"key":"master_prop_sheet","label":"Master Prop Sheet","default":true,"text":"Create a Professional Film Prop Design Sheet based ONLY on the prop description below.\n\nSTYLE\nHollywood prop department documentation.\nLuxury industrial design.\nPhotorealistic concept rendering.\n\nDISPLAY — ONE hero view only, nothing else:\n• Hero — a single, clear, well-lit view of the prop that best shows its described features\n\nFIELD DISCIPLINE (critical)\n• Only show details that are actually in the prop description below — never invent materials, finishes, or features that weren''t described.\n• Do not generate additional angles (front/back/left/right/top/bottom), turnarounds, or texture-sample grids — one hero view, one image.\n\nANNOTATIONS\nMaterials, finish, functional parts, usage — only where the description actually specifies them.\n\nOUTPUT\nGenerate ONE official prop reference image — a single image, not a multi-angle turnaround."}]},"sound":{"label":"Sound","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now.","content":{"geminiInstruction":"Describe the sound/music direction for this project. A short, specific, production-usable description — not a placeholder.","fieldsSchema":[{"key":"description","label":"Description","type":"textarea"}]},"outputInstructions":[{"key":"master_music_sheet","label":"Master Music / Sound Design Sheet","default":true,"text":"Create a Professional Music & Sound Design Board based ONLY on the creative brief below.\n\nDISPLAY\nPrimary Mood\nSecondary Mood\nGenre\nTempo\nEnergy Curve\nInstrumentation\nRhythm\nScene Timing\nSound FX\nAmbient Layer\nSilence Moments\nTransition Notes\nVoice-over Mood\n\nOUTPUT\nCreative audio brief used by award-winning advertising agencies."}]},"background":{"label":"Background","note":"Reinstated per request.","content":{"geminiInstruction":"Describe the background/location for use as a visual reference: location, lighting, style. A short, specific, production-usable description — not a placeholder.","fieldsSchema":[{"key":"location","label":"Location","type":"text"},{"key":"lighting","label":"Lighting","type":"pill","options":["Morning Natural","Golden Hour","Studio Softbox","Overcast","Night Neon"]},{"key":"style","label":"Style","type":"pill","options":["Minimal","Rustic","Luxury","Industrial","Cozy"]}]},"outputInstructions":[{"key":"master_background_sheet","label":"Master Background / Location Sheet","default":true,"text":"Create a Premium Cinematic Environment Design Board based ONLY on the location description below.\n\nSTYLE\nHollywood production design.\nArchitectural visualization.\nAdvertising art direction.\n\nDISPLAY — ONE view only, nothing else:\n• Hero Wide — a single, clear wide view of the location, at the specific time of day/lighting and in the specific style described below\n\nFIELD DISCIPLINE (critical)\n• Use exactly the location, lighting, and style described below — never substitute a different location, and never default to a generic or previous example.\n• Do not generate multiple lighting/time variants (morning/afternoon/golden hour/night), multiple angles, floor plans, material palettes, or texture-sample grids — one location, one lighting condition, one image.\n\nANNOTATIONS\nCamera position and composition suggestions, only where relevant to this one image.\n\nOUTPUT\nGenerate ONE professional location reference image — a single image, not a multi-view mood board."}]}}}', updated_at = datetime('now') WHERE stage = 3;